async function initDIDMapping() {
  await pool.query(`
    CREATE TABLE IF NOT EXISTS did_account_map (
      did TEXT PRIMARY KEY,
      account_id TEXT NOT NULL,
      updated_at TIMESTAMP DEFAULT NOW()
    );
    CREATE INDEX IF NOT EXISTS did_account_idx ON did_account_map(account_id);
  `);
}
initDIDMapping().catch(console.error);

// Save DIDs for an account
app.post('/api/did-map', async (req, res) => {
  try {
    const { dids, account_id } = req.body;
    const acct = account_id || req.headers['x-account-id'] || 'ezfinance';
    if (!dids || !Array.isArray(dids)) return res.status(400).json({ error: 'DIDs array required' });
    for (const did of dids) {
      const clean = String(did).replace(/\D/g, '').slice(-10);
      if (clean.length === 10) {
        await pool.query('INSERT INTO did_account_map (did, account_id, updated_at) VALUES ($1,$2,NOW()) ON CONFLICT (did) DO UPDATE SET account_id=$2, updated_at=NOW()', [clean, acct]);
      }
    }
    res.json({ ok: true, mapped: dids.length });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// Get DIDs for an account
app.get('/api/did-map', async (req, res) => {
  try {
    const acct = req.query.account_id || req.headers['x-account-id'] || 'ezfinance';
    const r = await pool.query('SELECT did FROM did_account_map WHERE account_id=$1 ORDER BY updated_at DESC', [acct]);
    res.json(r.rows.map(row => row.did));
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// Get all DID mappings
app.get('/api/did-map/all', async (req, res) => {
  try {
    const r = await pool.query('SELECT did, account_id FROM did_account_map ORDER BY account_id, did');
    res.json(r.rows);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// Delete a DID mapping
app.delete('/api/did-map/:did', async (req, res) => {
  try {
    const clean = req.params.did.replace(/\D/g, '').slice(-10);
    await pool.query('DELETE FROM did_account_map WHERE did=$1', [clean]);
    res.json({ ok: true });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

