// Load carrier map into DB on startup if not already there
async function initCarrierMap() {
  try {
    const r = await pool.query("SELECT key FROM config WHERE key='carrier_map'");
    if (r.rows.length === 0) {
      await pool.query('INSERT INTO config (key,value,updated_at) VALUES ($1,$2,NOW()) ON CONFLICT (key) DO NOTHING', 
        ['carrier_map', JSON.stringify(CARRIER_MAP_DATA)]);
      console.log('Carrier map loaded:', Object.keys(CARRIER_MAP_DATA).length, 'entries');
    }
    carrierMapCache = CARRIER_MAP_DATA;
  } catch(e) { console.error('Carrier map init error:', e.message); }
}
initCarrierMap();

async function getCarrierMap() {
  if (carrierMapCache) return carrierMapCache;
  try {
    const r = await pool.query("SELECT value FROM config WHERE key='carrier_map'");
    if (r.rows.length > 0) {
      carrierMapCache = JSON.parse(r.rows[0].value);
      return carrierMapCache;
    }
  } catch(e) {}
  return {};
}

// Upload carrier map
app.post('/api/carrier-map', async (req, res) => {
  try {
    const { map } = req.body;
    if (!map) return res.status(400).json({ error: 'No map provided' });
    await pool.query('INSERT INTO config (key,value,updated_at) VALUES ($1,$2,NOW()) ON CONFLICT (key) DO UPDATE SET value=$2,updated_at=NOW()', ['carrier_map', JSON.stringify(map)]);
    carrierMapCache = map;
    res.json({ ok: true, entries: Object.keys(map).length });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// Scrub a list of numbers - returns carrier tags
app.post('/api/scrub', async (req, res) => {
  try {
    const { numbers } = req.body;
    if (!numbers || !Array.isArray(numbers)) return res.status(400).json({ error: 'Numbers array required' });
    const map = await getCarrierMap();
    const results = numbers.map(num => {
      const clean = String(num).replace(/\D/g, '');
      const tenDigit = clean.length === 11 && clean[0] === '1' ? clean.slice(1) : clean.slice(-10);
      const npa_nxx = tenDigit.slice(0, 6);
      const carrier = map[npa_nxx] || 'unknown';
      return { number: tenDigit, carrier };
    });
    const summary = results.reduce((acc, r) => { acc[r.carrier] = (acc[r.carrier]||0)+1; return acc; }, {});
    res.json({ ok: true, results, summary });
  } catch(e) { res.status(500).json({ error: e.message }); }
});


