  await pool.query("ALTER TABLE wsm_leads ADD COLUMN IF NOT EXISTS meeting_time TIMESTAMP");
  await pool.query("ALTER TABLE wsm_leads ADD COLUMN IF NOT EXISTS reminder_24h BOOLEAN DEFAULT FALSE");
  await pool.query("ALTER TABLE wsm_leads ADD COLUMN IF NOT EXISTS reminder_1h BOOLEAN DEFAULT FALSE");
  await pool.query("ALTER TABLE wsm_leads ADD COLUMN IF NOT EXISTS reminder_2min BOOLEAN DEFAULT FALSE");
  await pool.query("ALTER TABLE wsm_leads ADD COLUMN IF NOT EXISTS no_show_count INTEGER DEFAULT 0");

