// Setup Calendly webhook on startup
async function setupCalendlyWebhook() {
  try {
    // Get user info
    console.log('Calendly token length:', CALENDLY_TOKEN ? CALENDLY_TOKEN.length : 0);
    const userResp = await fetch('https://api.calendly.com/users/me', {
      headers: { 'Authorization': 'Bearer ' + CALENDLY_TOKEN, 'Content-Type': 'application/json' }
    });
    console.log('Calendly user response status:', userResp.status);
    const userData = await userResp.json();
    console.log('Calendly user:', JSON.stringify(userData).slice(0, 200));
    
    const userUri = userData.resource && userData.resource.uri;
    const orgUri = userData.resource && userData.resource.current_organization;
    
    if (!userUri) { console.log('Could not get Calendly user URI'); return; }
    
    const webhookUrl = 'https://sms-blast-backend-production.up.railway.app/webhook/calendly';
    
    // Check existing webhooks
    const existing = await fetch('https://api.calendly.com/webhook_subscriptions?scope=user&user=' + encodeURIComponent(userUri) + '&organization=' + encodeURIComponent(orgUri), {
      headers: { 'Authorization': 'Bearer ' + CALENDLY_TOKEN }
    });
    const existingData = await existing.json();
    console.log('Existing webhooks:', JSON.stringify(existingData).slice(0, 300));
    
    const alreadyExists = existingData.collection && existingData.collection.some(w => w.callback_url === webhookUrl);
    if (alreadyExists) { console.log('Calendly webhook already exists'); return; }
    
    // Create webhook
    const createResp = await fetch('https://api.calendly.com/webhook_subscriptions', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + CALENDLY_TOKEN, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        url: webhookUrl,
        events: ['invitee.created', 'invitee.canceled'],
        organization: orgUri,
        user: userUri,
        scope: 'user'
      })
    });
    const createData = await createResp.json();
    console.log('Calendly webhook created:', JSON.stringify(createData).slice(0, 300));
  } catch(e) { console.log('Calendly webhook setup error:', e.message); }
}
setTimeout(setupCalendlyWebhook, 5000);

