function getTemplateForIndustry(industry) {
  if (!industry) return INDUSTRY_TEMPLATES['default'];
  // Exact match first
  if (INDUSTRY_TEMPLATES[industry]) return INDUSTRY_TEMPLATES[industry];
  // Partial match
  const industryLower = industry.toLowerCase();
  for (const [key, template] of Object.entries(INDUSTRY_TEMPLATES)) {
    if (key !== 'default' && industryLower.includes(key.toLowerCase().split(' ')[0])) {
      return template;
    }
  }
  return INDUSTRY_TEMPLATES['default'];
}

