// Analytics endpoint
app.get('/api/analytics', async (req, res) => {
  try {
    const acct = req.query.account_id || req.headers['x-account-id'] || 'wallstreetmedia';
    
    const [byIndustry, byState, byHour, byDay, topTemplates] = await Promise.all([
      // Reply rate by industry
      pool.query(`
        SELECT industry, 
          COUNT(*) as total,
          SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) as replies,
          SUM(CASE WHEN got_booking THEN 1 ELSE 0 END) as bookings,
          ROUND(100.0 * SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) / NULLIF(COUNT(*),0), 2) as reply_rate
        FROM msg_analytics WHERE account_id=$1
        GROUP BY industry ORDER BY reply_rate DESC LIMIT 20
      `, [acct]),
      
      // Reply rate by state
      pool.query(`
        SELECT state,
          COUNT(*) as total,
          SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) as replies,
          ROUND(100.0 * SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) / NULLIF(COUNT(*),0), 2) as reply_rate
        FROM msg_analytics WHERE account_id=$1 AND state IS NOT NULL
        GROUP BY state ORDER BY reply_rate DESC LIMIT 20
      `, [acct]),
      
      // Best hours
      pool.query(`
        SELECT hour_sent,
          COUNT(*) as total,
          SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) as replies,
          ROUND(100.0 * SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) / NULLIF(COUNT(*),0), 2) as reply_rate
        FROM msg_analytics WHERE account_id=$1
        GROUP BY hour_sent ORDER BY hour_sent
      `, [acct]),
      
      // Best days
      pool.query(`
        SELECT day_of_week,
          COUNT(*) as total,
          SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) as replies,
          ROUND(100.0 * SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) / NULLIF(COUNT(*),0), 2) as reply_rate
        FROM msg_analytics WHERE account_id=$1
        GROUP BY day_of_week ORDER BY day_of_week
      `, [acct]),
      
      // Top campaigns
      pool.query(`
        SELECT campaign,
          COUNT(*) as total,
          SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) as replies,
          ROUND(100.0 * SUM(CASE WHEN got_reply THEN 1 ELSE 0 END) / NULLIF(COUNT(*),0), 2) as reply_rate
        FROM msg_analytics WHERE account_id=$1
        GROUP BY campaign ORDER BY reply_rate DESC LIMIT 10
      `, [acct])
    ]);
    
    res.json({
      by_industry: byIndustry.rows,
      by_state: byState.rows,
      by_hour: byHour.rows,
      by_day: byDay.rows,
      top_campaigns: topTemplates.rows
    });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

