// Meeting reminder checker - runs every minute
async function checkMeetingReminders() {
  try {
    const leads = await pool.query(`
      SELECT * FROM wsm_leads 
      WHERE booked=true 
      AND meeting_time IS NOT NULL 
      AND meeting_time > NOW()
      AND (reminder_24h=false OR reminder_1h=false OR reminder_2min=false)
    `);
    
    const now = new Date();
    
    for (const lead of leads.rows) {
      const meetingTime = new Date(lead.meeting_time);
      const minutesUntil = (meetingTime - now) / (1000 * 60);
      
      const didRow = await pool.query("SELECT frm FROM msgs WHERE tod=$1 AND account_id='wallstreetmedia' AND dir='outbound' ORDER BY ts DESC LIMIT 1", [lead.phone]);
      if (!didRow.rows.length) continue;
      const fromDID = didRow.rows[0].frm;
      
      // 24 hour reminder
      if (!lead.reminder_24h && minutesUntil <= 1440 && minutesUntil > 60) {
        const msg = `Reminder: Your free website preview for ${lead.company||'your business'} with Wall Street Media is tomorrow at ${meetingTime.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',timeZone:'America/New_York'})} EST. See you then! Need to reschedule? ${CALENDLY_LINK}`;
        await sendWSMSMS(fromDID, lead.phone, msg);
        await pool.query('UPDATE wsm_leads SET reminder_24h=true WHERE phone=$1', [lead.phone]);
        console.log('24hr reminder sent to', lead.phone);
      }
      
      // 1 hour reminder
      if (!lead.reminder_1h && minutesUntil <= 60 && minutesUntil > 5) {
        const msg = `Your website preview is in 1 hour! ${meetingTime.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',timeZone:'America/New_York'})} EST. We'll be ready to show you what we built for ${lead.company||'your business'}!`;
        await sendWSMSMS(fromDID, lead.phone, msg);
        await pool.query('UPDATE wsm_leads SET reminder_1h=true WHERE phone=$1', [lead.phone]);
        console.log('1hr reminder sent to', lead.phone);
      }
      
      // 2 minute reminder
      if (!lead.reminder_2min && minutesUntil <= 2 && minutesUntil > 0) {
        const msg = `We're going live in 2 minutes! Join the Zoom now for your website preview. Can't make it? Reschedule here: ${CALENDLY_LINK} or call (954) 271-5693`;
        await sendWSMSMS(fromDID, lead.phone, msg);
        await pool.query('UPDATE wsm_leads SET reminder_2min=true WHERE phone=$1', [lead.phone]);
        console.log('2min reminder sent to', lead.phone);
      }
    }
  } catch(e) { console.error('Reminder checker error:', e.message); }
}
setInterval(checkMeetingReminders, 60 * 1000);

