// ─── WEBHOOKS ────────────────────────────────────────────────────────
app.post('/webhook/dlr', async (req, res) => {
  try {
    let b; try { b = Buffer.isBuffer(req.body) ? JSON.parse(req.body.toString()) : req.body; } catch(e) { b = {}; }
    console.log('DLR received:', JSON.stringify(b));
    // Try all possible GUID fields from Commio new endpoint
    const guid = b.guid || b.sms_guid || b.message_id || b.id || 
                 (b.data && b.data.results && b.data.results[0] && b.data.results[0].messageId) ||
                 (b.data && b.data.batchId);
    const sc = String(b.status || b.send_status || b.delivery_status || '').toUpperCase();
    let stat = 'SENT';
    if (sc === 'DELIVRD' || sc === 'DELIVERED' || sc.includes('DELIVER')) stat = 'DELIVERED';
    else if (sc === 'REJECTED' || sc.includes('FAIL') || sc === '600' || sc === '800') stat = 'FAILED';
    else if (sc.includes('UNDELIVER')) stat = 'UNDELIVERED';
    console.log('DLR guid:', guid, 'status:', stat, 'raw status:', sc);
    const errorCode = String(b.error || b.error_code || '').trim();
    if (guid) {
      const r = await pool.query('UPDATE msgs SET stat=$1, error_code=$2 WHERE guid=$3 RETURNING id', [stat, errorCode, guid]);
      console.log('DLR updated rows:', r.rowCount);
      if (r.rowCount === 0) {
        const r2 = await pool.query("UPDATE msgs SET stat=$1, error_code=$2 WHERE guid ILIKE $3 RETURNING id", [stat, errorCode, '%' + guid.slice(-12) + '%']);
        console.log('DLR partial match rows:', r2.rowCount);
      }
    }
    res.json({ ok: true });
  } catch(e) { console.error('DLR error:', e); res.status(500).json({ error: e.message }); }
});

app.post('/webhook/inbound', async (req, res) => {
  try {
    let b; try { b = Buffer.isBuffer(req.body) ? JSON.parse(req.body.toString()) : req.body; } catch(e) { b = {}; }
    console.log('Inbound:', JSON.stringify(b));
    const frm = String(b.from || b.from_did || '').replace(/\D/g, '').slice(-10);
    const tod = String(b.to || b.to_did || '').replace(/\D/g, '').slice(-10);
    const msg = b.message || b.text || '';
    const guid = b.guid || ('in_' + Date.now());
    if (!frm || !tod) return res.json({ ok: true });
    // Detect account from DID account map first, then fall back to outbound lookup
    let inboundAcct = 'ezfinance';
    try {
      // Check DID map first — most reliable
      const didMapRow = await pool.query('SELECT account_id FROM did_account_map WHERE did=$1', [tod]);
      if (didMapRow.rows.length > 0) {
        inboundAcct = didMapRow.rows[0].account_id;
      } else {
        // Fall back to most recent outbound message lookup
        const outboundRow = await pool.query(
          "SELECT account_id FROM msgs WHERE tod=$1 AND dir='outbound' AND account_id IS NOT NULL ORDER BY ts DESC LIMIT 1",
          [frm]
        );
        if (outboundRow.rows.length > 0 && outboundRow.rows[0].account_id) {
          inboundAcct = outboundRow.rows[0].account_id;
        }
      }
      console.log('Inbound routed to account:', inboundAcct, 'for DID:', tod);
    } catch(e) { console.log('Account lookup error:', e.message); }
    await pool.query('INSERT INTO msgs (guid,frm,tod,msg,dir,stat,account_id) VALUES ($1,$2,$3,$4,$5,$6,$7) ON CONFLICT (guid) DO NOTHING', [guid, frm, tod, msg, 'inbound', 'DELIVERED', inboundAcct]);
    await pool.query('INSERT INTO convos (cnum,onum,lastmsg,lastts,unread,account_id) VALUES ($1,$2,$3,NOW(),1,$4) ON CONFLICT (cnum,onum) DO UPDATE SET lastmsg=$3,lastts=NOW(),unread=convos.unread+1', [frm, tod, msg, inboundAcct]);
    // Auto-add to DNC if STOP/CANCEL/UNSUBSCRIBE/END/QUIT
    const stopWords = ['stop','cancel','unsubscribe','end','quit','optout','opt out','opt-out'];
    if (stopWords.some(w => msg.toLowerCase().trim().includes(w))) {
      await pool.query('INSERT INTO dnc (phone,reason) VALUES ($1,$2) ON CONFLICT (phone) DO NOTHING', [frm, 'STOP reply']);
      console.log('Added to DNC:', frm, '- reason: STOP reply');
    }
    console.log('Saved inbound from', frm, 'to', tod);
    
    // Trigger WSM AI for wallstreetmedia account
    if (inboundAcct === 'wallstreetmedia') {
      handleWSMInbound(frm, msg, tod).catch(e => console.error('WSM handler error:', e.message));
    }
    
    res.json({ ok: true });
  } catch(e) { console.error('Inbound error:', e.message); res.status(500).json({ error: e.message }); }
});

