app.get('/api/export', async (req, res) => {
  try {
    const { campaign } = req.query;
    let q = "SELECT frm as from_number, tod as to_number, msg as message, stat as status, error_code, cname as campaign, ts as timestamp FROM msgs WHERE dir='outbound'";
    const params = [];
    if (campaign) { q += ' AND cname=$1'; params.push(campaign); }
    q += ' ORDER BY ts DESC';
    const r = await pool.query(q, params);
    const csv = ['From,To,Message,Status,Error Code,Error Description,Campaign,Timestamp',
      ...r.rows.map(row => {
        const errorDescs = {'600':'Carrier rejected','800':'Filtered by carrier','000':'Delivered','100':'Delivered','400':'Bad request','500':'Server error'};
        const errDesc = row.error_code ? (errorDescs[row.error_code] || 'Unknown') : '';
        return `${row.from_number},${row.to_number},"${(row.message||'').replace(/"/g,'""')}",${row.status},${row.error_code||''},${errDesc},${row.campaign||''},${row.timestamp}`;
      })
    ].join('\n');
    res.setHeader('Content-Type', 'text/csv');
    res.setHeader('Content-Disposition', 'attachment; filename="messages.csv"');
    res.send(csv);
  } catch(e) { res.status(500).json({ error: e.message }); }
});



// Export messages that were sent but never delivered (for carrier investigation)
app.get('/api/export/undelivered', async (req, res) => {
  try {
    const { campaign, limit = 100 } = req.query;
    let q = "SELECT frm as from_number, tod as to_number, msg as message, stat as status, error_code, cname as campaign, ts as timestamp, guid FROM msgs WHERE dir='outbound' AND stat='SENT'";
    const params = [];
    if (campaign) { q += ' AND cname=$1'; params.push(campaign); }
    q += ' ORDER BY ts DESC LIMIT $' + (params.length + 1);
    params.push(limit);
    const r = await pool.query(q, params);
    const csv = ['GUID,From,To,Message,Status,Error Code,Campaign,Timestamp',
      ...r.rows.map(row => `${row.guid},${row.from_number},${row.to_number},"${(row.message||'').replace(/"/g,'""')}",${row.status},${row.error_code||''},${row.campaign||''},${row.timestamp}`)
    ].join('\n');
    res.setHeader('Content-Type', 'text/csv');
    res.setHeader('Content-Disposition', 'attachment; filename="undelivered-messages.csv"');
    res.send(csv);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

// Export inbound messages as CSV
app.get('/api/export/inbound', async (req, res) => {
  try {
    const { date } = req.query;
    let q = "SELECT frm as from_number, tod as to_number, msg as message, stat as status, ts as timestamp FROM msgs WHERE dir='inbound'";
    const params = [];
    if (date) {
      q += ' AND ts::date = $1';
      params.push(date);
    } else {
      q += " AND ts >= NOW() - INTERVAL '24 hours'";
    }
    q += ' ORDER BY ts DESC';
    const r = await pool.query(q, params);
    const csv = ['From,To,Message,Status,Timestamp',
      ...r.rows.map(row => `${row.from_number},${row.to_number},"${(row.message||'').replace(/"/g,'""')}",${row.status||''},${row.timestamp}`)
    ].join('\n');
    res.setHeader('Content-Type', 'text/csv');
    res.setHeader('Content-Disposition', 'attachment; filename="replies-' + (date || 'today') + '.csv"');
    res.send(csv);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

