// Admin endpoints — see all accounts
app.get('/api/admin/stats', async (req, res) => {
  try {
    const { key } = req.query;
    if (key !== 'rsbrm#7') return res.status(401).json({ error: 'Unauthorized' });
    const accounts = ['ezfinance', 'wallstreetmedia'];
    const stats = {};
    for (const acct of accounts) {
      const [total, delivered, failed, inbound, unread] = await Promise.all([
        pool.query("SELECT COUNT(*) as n FROM msgs WHERE dir='outbound' AND account_id=$1", [acct]),
        pool.query("SELECT COUNT(*) as n FROM msgs WHERE stat='DELIVERED' AND account_id=$1", [acct]),
        pool.query("SELECT COUNT(*) as n FROM msgs WHERE stat='FAILED' AND account_id=$1", [acct]),
        pool.query("SELECT COUNT(*) as n FROM msgs WHERE dir='inbound' AND account_id=$1", [acct]),
        pool.query('SELECT SUM(unread) as n FROM convos WHERE account_id=$1', [acct])
      ]);
      stats[acct] = { total: +total.rows[0].n, delivered: +delivered.rows[0].n, failed: +failed.rows[0].n, inbound: +inbound.rows[0].n, unread: +(unread.rows[0].n||0) };
    }
    res.json(stats);
  } catch(e) { res.status(500).json({ error: e.message }); }
});

